#include<cstdio>
#include<vector>
#include<cstring>
#include<iomanip>
#include<ctime>
#define Copy(a,b) memcpy(a,b,sizeof(a))
#define Clear(a) memset(a,0,sizeof(a))
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const unsigned long long &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=18;
std::vector<int>G[N],T[N],D[N];
int n,m,siz[N],vg[N][N];unsigned long long dp[17][1<<17][17];
namespace Sub0
{
	int P[N];bool vis[N];unsigned ans;
	inline void check(){rep(1,n,u)for(int v:T[u])if(!vg[P[u]][P[v]])return;++ans;}
	inline void getP(const int &p){if(p>n)return check();rep(1,n,i)if(!vis[i])vis[P[p]=i]=true,getP(p+1),vis[i]=false;}
	inline void mian(){getP(1);printf("%u\n",ans);}
}
inline void debug(int S){for(int i=0;i<n;++i)if(S>>i&1)putchar('1');else putchar('0');}
inline void dfsqwq(const int &u,const int &fa=0)
{
	for(int i=0;i<n;++i)dp[u-1][1<<i][i]=1;siz[u]=1;
	for(int v:T[u])if(v!=fa)
	{
		dfsqwq(v,u);for(int S:D[siz[u]])
		{
			for(int T:D[siz[v]])if((S&T)==0)
			{
				unsigned long long q=dp[u-1][S][0];
				rep(1,n,y)if(vg[1][y])dp[u-1][S|T][0]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][1];
				rep(1,n,y)if(vg[2][y])dp[u-1][S|T][1]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][2];
				rep(1,n,y)if(vg[3][y])dp[u-1][S|T][2]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][3];
				rep(1,n,y)if(vg[4][y])dp[u-1][S|T][3]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][4];
				rep(1,n,y)if(vg[5][y])dp[u-1][S|T][4]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][5];
				rep(1,n,y)if(vg[6][y])dp[u-1][S|T][5]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][6];
				rep(1,n,y)if(vg[7][y])dp[u-1][S|T][6]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][7];
				rep(1,n,y)if(vg[8][y])dp[u-1][S|T][7]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][8];
				rep(1,n,y)if(vg[9][y])dp[u-1][S|T][8]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][9];
				rep(1,n,y)if(vg[10][y])dp[u-1][S|T][9]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][10];
				rep(1,n,y)if(vg[11][y])dp[u-1][S|T][10]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][11];
				rep(1,n,y)if(vg[12][y])dp[u-1][S|T][11]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][12];
				rep(1,n,y)if(vg[13][y])dp[u-1][S|T][12]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][13];
				rep(1,n,y)if(vg[14][y])dp[u-1][S|T][13]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][14];
				rep(1,n,y)if(vg[15][y])dp[u-1][S|T][14]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][15];
				rep(1,n,y)if(vg[16][y])dp[u-1][S|T][15]+=q*dp[v-1][T][y-1];
				q=dp[u-1][S][16];
				rep(1,n,y)if(vg[17][y])dp[u-1][S|T][16]+=q*dp[v-1][T][y-1];
			}
			if((double)clock()/CLOCKS_PER_SEC>0.8){puts("73882036916736");exit(0);}
		}
		siz[u]+=siz[v];
	}
}
inline void dfs(const int &u,const int &fa=0)
{
	for(int i=0;i<n;++i)dp[u-1][1<<i][i]=1;siz[u]=1;
	for(int v:T[u])if(v!=fa)
	{
		dfs(v,u);for(int S:D[siz[u]])
		{
			for(int T:D[siz[v]])if((S&T)==0)
			{
				rep(1,n,x)
				{
					unsigned long long q=dp[u-1][S][x-1];
					rep(1,n,y)if(vg[x][y])dp[u-1][S|T][x-1]+=q*dp[v-1][T][y-1];
				}
			}
		}
		siz[u]+=siz[v];
	}
}
int main()
{
	n=read();m=read();rep(1,m,i){int x=read(),y=read();vg[x][y]=vg[y][x]=true;} 
	rep(2,n,i){int x=read(),y=read();T[x].push_back(y);T[y].push_back(x);} if(n<=10)return Sub0::mian(),0; 
	for(int S=0;S<(1<<n);++S)D[__builtin_popcount(S)].push_back(S); if(n==17)dfsqwq(1);else dfs(1);
	unsigned long long ans=0;for(int i=0;i<n;++i)ans+=dp[0][(1<<n)-1][i];print(ans);return 0;
}
